// src/Menu.js
import React, { useState, useEffect } from 'react';
import axios                        from 'axios';
import './Menu.css';

const Menu = () => {
    // bestaande state
    const [menuItems, setMenuItems] = useState([]);
    const [loading,   setLoading]   = useState(true);
    const [error,     setError]     = useState(null);
    const [editMode,  setEditMode]  = useState(false);
    const [priceMap,  setPriceMap]  = useState({});
    const [toDelete,  setToDelete]  = useState(new Set());

    // nieuwe state voor “add form”
    const [productsList,   setProductsList]   = useState([]);
    const [categories,     setCategories]     = useState([]);
    const [subcategories,  setSubcategories]  = useState([]);
    const [newItem,        setNewItem]        = useState({
        productId: '', name: '', brand: '', category: '', subcategory: '', price: ''
    });

    // 1) Initial fetch menu + lookup-data
    useEffect(() => {
        const fetchAll = async () => {
            try {
                const [menuRes, prodRes, catRes, subRes] = await Promise.all([
                    axios.get('http://localhost:3007/api/menu-items',    { withCredentials: true }),
                    axios.get('http://localhost:3007/api/products',      { withCredentials: true }),
                    axios.get('http://localhost:3007/api/categories',    { withCredentials: true }),
                    axios.get('http://localhost:3007/api/subcategories', { withCredentials: true })
                ]);
                setMenuItems(menuRes.data);
                setProductsList(prodRes.data);
                setCategories(catRes.data);
                setSubcategories(subRes.data);
            } catch (err) {
                console.error(err);
                setError('Kon data niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchAll();
    }, []);

    // 2) seed priceMap & reset deletions bij editMode
    useEffect(() => {
        if (editMode) {
            const m = {};
            menuItems.forEach(i => m[i.id_menu_item] = i.price);
            setPriceMap(m);
            setToDelete(new Set());
        }
    }, [editMode, menuItems]);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // handlers
    const handlePriceChange = (id, raw) => {
        const v = parseFloat(raw);
        setPriceMap(pm => ({
            ...pm,
            [id]: isNaN(v) ? raw : v
        }));
    };
    const toggleDelete = id => {
        setToDelete(td => {
            const nxt = new Set(td);
            nxt.has(id) ? nxt.delete(id) : nxt.add(id);
            return nxt;
        });
    };
    const handleCancel = () => {
        setEditMode(false);
        setPriceMap({});
        setToDelete(new Set());
    };

    // Confirm = eerst DELETE, dan PATCH prijzen
    const handleSave = async () => {
        try {
            // 1) gemarkeerde items verwijderen
            for (let id of toDelete) {
                await axios.delete(
                    `http://localhost:3007/api/menu-items/${id}`,
                    { withCredentials: true }
                );
            }
            // 2) prijzen updaten
            const updates = Object.entries(priceMap)
                .filter(([id,_]) => !toDelete.has(Number(id)))
                .map(([id, price]) => ({
                    id_menu_item: Number(id),
                    price:        Number(price)
                }));
            if (updates.length) {
                await axios.patch(
                    'http://localhost:3007/api/menu-items',
                    { updates },
                    { withCredentials: true }
                );
            }
            // 3) alles herladen
            const res = await axios.get('http://localhost:3007/api/menu-items', {
                withCredentials: true
            });
            setMenuItems(res.data);
            setEditMode(false);
            setToDelete(new Set());
        } catch (err) {
            console.error(err);
            alert('Opslaan mislukt');
        }
    };

    // 4) nieuwe item toevoegen
    const handleAdd = async e => {
        e.preventDefault();
        try {
            // product moet bestaan → gebruik productId
            const pid = newItem.productId;
            // invoegen in menu_items
            await axios.post(
                'http://localhost:3007/api/menu-items',
                {
                    product_id: pid,
                    price:      Number(newItem.price)
                },
                { withCredentials: true }
            );
            // herlaad menu
            const res = await axios.get('http://localhost:3007/api/menu-items', {
                withCredentials: true
            });
            setMenuItems(res.data);
            // reset form
            setNewItem({ productId:'', name:'', brand:'', category:'', subcategory:'', price:'' });
        } catch (err) {
            console.error(err);
            alert('Toevoegen mislukt');
        }
    };

    // groep per category
    const grouped = menuItems.reduce((acc, item) => {
        if (!acc[item.category]) acc[item.category] = [];
        acc[item.category].push(item);
        return acc;
    }, {});

    return (
        <div className="menu-container">
            {/* ──────── Form “Nieuw item” ───────── */}
            <form className="add-form" onSubmit={handleAdd}>
                {/* autocomplete bestaande producten */}
                <input
                    list="products-dl"
                    placeholder="Item naam…"
                    value={newItem.name}
                    onChange={e => {
                        const val = e.target.value;
                        setNewItem(ni => ({ ...ni, name: val }));
                        // als match met bestaand product, vul automatisch
                        const match = productsList.find(p => p.name === val);
                        if (match) {
                            setNewItem(ni => ({
                                ...ni,
                                productId:     match.id_product,
                                brand:         match.brand,
                                category:      String(match.id_category),
                                subcategory:   String(match.id_subcategory)
                            }));
                        } else {
                            setNewItem(ni => ({ ...ni, productId: '' }));
                        }
                    }}
                />
                <datalist id="products-dl">
                    {productsList.map(p => (
                        <option key={p.id_product} value={p.name}/>
                    ))}
                </datalist>

                {/* brand */}
                <input
                    type="text"
                    placeholder="Brand"
                    value={newItem.brand}
                    onChange={e => setNewItem(ni => ({ ...ni, brand: e.target.value }))}
                    required
                />

                {/* category */}
                <select
                    value={newItem.category}
                    onChange={e => setNewItem(ni => ({
                        ...ni,
                        category:    e.target.value,
                        subcategory: ''    // reset subcat
                    }))}
                    required
                >
                    <option value="">-- Kies categorie --</option>
                    {categories.map(c => (
                        <option key={c.id_category} value={c.id_category}>
                            {c.category_name}
                        </option>
                    ))}
                </select>

                {/* subcategory (gefilterd op gekozen category) */}
                <select
                    value={newItem.subcategory}
                    onChange={e => setNewItem(ni => ({ ...ni, subcategory: e.target.value }))}
                    required
                >
                    <option value="">-- Kies subcategorie --</option>
                    {subcategories
                        .filter(sc => sc.id_category === Number(newItem.category))
                        .map(sc => (
                            <option key={sc.id_subcat} value={sc.id_subcat}>
                                {sc.subcat_name}
                            </option>
                        ))}
                </select>

                {/* price */}
                <input
                    type="number"
                    step="0.01"
                    placeholder="Prijs"
                    value={newItem.price}
                    onChange={e => setNewItem(ni => ({ ...ni, price: e.target.value }))}
                    required
                />

                <button type="submit" className="add-btn">
                    Voeg toe
                </button>
            </form>

            {/* ──── Bestaande menu ──── */}
            <div className="menu-header">
                {!editMode ? (
                    <button className="edit-save-btn" onClick={() => setEditMode(true)}>
                        Edit
                    </button>
                ) : (
                    <>
                        <button className="edit-save-btn" onClick={handleSave}>
                            Confirm
                        </button>
                        <button className="edit-cancel-btn" onClick={handleCancel}>
                            Cancel
                        </button>
                    </>
                )}
            </div>
            <div className="menu-list-container">
                {Object.entries(grouped).map(([category, items]) => (
                    <section key={category} className="menu-section">
                        <h3 className="menu-category">{category}</h3>
                        <ul className="menu-list">
                            {items.map(i => {
                                if (editMode && toDelete.has(i.id_menu_item)) return null;
                                return (
                                    <li key={i.id_menu_item} className="menu-item">
                                        {editMode && (
                                            <button
                                                className="delete-marker"
                                                onClick={() => toggleDelete(i.id_menu_item)}
                                                title="Verwijder dit item"
                                            >
                                                ×
                                            </button>
                                        )}
                                        <div className="item-name">{i.item_name}</div>
                                        <div className="item-brand">{i.producent}</div>
                                        <div className="item-price">
                                            {editMode ? (
                                                <div className="price-input-wrapper">
                                                    <span className="currency-symbol">€</span>
                                                    <input
                                                        type="number"
                                                        step="0.01"
                                                        className="menu-item-input"
                                                        value={priceMap[i.id_menu_item] ?? ''}
                                                        onChange={e =>
                                                            handlePriceChange(i.id_menu_item, e.target.value)
                                                        }
                                                    />
                                                </div>
                                            ) : (
                                                `€${Number(i.price).toFixed(2)}`
                                            )}
                                        </div>
                                    </li>
                                );
                            })}
                        </ul>
                    </section>
                ))}
            </div>
        </div>
    );
};

export default Menu;
